   335→/**
   336→ * Calculate enhanced scores by applying AI feature confidence boosts
   337→ */
   338→function calculateEnhancedScores(
   339→  candidateCategories: Record<string, number>,
   340→  extractedFeatures: FeatureExtractionData,
   341→  enhancementCalculations: EnhancementCalculation[],
   342→  validationErrors: string[]
   343→): Record<string, number> {
   344→  const enhancedScores: Record<string, number> = {};
   345→
   346→  // Validate extracted features format
   347→  if (!extractedFeatures.semantic_intent || !extractedFeatures.category_enhancements) {
   348→    validationErrors.push('Invalid extracted features format');
   349→    // Fallback to original scores without enhancement
   350→    return { ...candidateCategories };
   351→  }
   352→
   353→  for (const [category, originalScore] of Object.entries(candidateCategories)) {
   354→    let enhancedScore = originalScore;
   355→    let confidenceBoost = 0;
   356→    let boostReason = 'No feature enhancement';
   357→
   358→    // Apply AI feature enhancement if available
   359→    const categoryEnhancement = extractedFeatures.category_enhancements?.[category];
   360→    if (categoryEnhancement) {
   361→      confidenceBoost = categoryEnhancement.confidence_boost || 0;
   362→
   363→      // Apply positive boosts only when category applies, but apply negative boosts regardless
   364→      if (categoryEnhancement.applies || confidenceBoost < 0) {
   365→        enhancedScore = originalScore + originalScore * confidenceBoost;
   366→        boostReason = `Applied ${confidenceBoost > 0 ? 'positive' : 'negative'} confidence boost based on AI features`;
   367→      }
   368→    }
   369→
   370→    enhancedScores[category] = enhancedScore;
   371→
   372→    // Track enhancement calculation for explainability
   373→    enhancementCalculations.push({
   374→      category,
   375→      originalScore,
   376→      confidenceBoost,
   377→      enhancedScore,
   378→      boostReason,
   379→    });
   380→  }
   381→
