   385→/**
   386→ * Evaluate skip conditions to determine if AI classification should be bypassed
   387→ */
   388→function evaluateSkipConditions(
   389→  enhancedScores: Record<string, number>,
   390→  extractedFeatures: FeatureExtractionData,
   391→  config: AIClassificationConfig
   392→): AIRoutingDecision {
   393→  const skipConditionsEvaluated: string[] = [];
   394→
   395→  // Find highest scoring category
   396→  const maxScore = Math.max(...Object.values(enhancedScores));
   397→
   398→  // Check for hard assertion condition first (highest priority)
   399→  if (config.skipConditions.skipReasons.includes('hard_assertion')) {
   400→    skipConditionsEvaluated.push('hard_assertion');
   401→    if ((extractedFeatures as unknown as Record<string, unknown>).hard_assertion_detected) {
   402→      return {
   403→        routedToAI: false,
   404→        reason: 'hard_assertion',
   405→        skipConditionsEvaluated,
   406→        decisionRationale: 'Hard assertion detected in earlier pipeline stage',
   407→      };
   408→    }
   409→  }
   410→
   411→  // Check high confidence threshold
   412→  skipConditionsEvaluated.push('high_confidence_threshold');
   413→  if (maxScore >= config.skipConditions.highConfidenceThreshold) {
   414→    return {
   415→      routedToAI: false,
   416→      reason: 'high_confidence',
   417→      confidenceScore: maxScore,
   418→      threshold: config.skipConditions.highConfidenceThreshold,
   419→      skipConditionsEvaluated,
   420→      decisionRationale: `Highest category score (${maxScore}) exceeds high confidence threshold (${config.skipConditions.highConfidenceThreshold})`,
   421→    };
   422→  }
   423→
   424→  // Default: route to AI
   425→  return {
   426→    routedToAI: true,
   427→    reason: 'requires_ai_classification',
   428→    skipConditionsEvaluated,
   429→    decisionRationale: `Confidence scores require AI classification (max: ${maxScore}, threshold: ${config.skipConditions.highConfidenceThreshold})`,
   430→  };
   431→}
   432→
   433→/**
   434→ * Create direct classification result when AI is skipped
   435→ */
   436→function createDirectClassification(enhancedScores: Record<string, number>, skipReason: string): FinalClassification {
   437→  // Sort categories by score descending
   438→  const sortedCategories = Object.entries(enhancedScores)
   439→    .sort(([, a], [, b]) => b - a)
   440→    .filter(([, score]) => score > 0);
   441→
   442→  if (sortedCategories.length === 0) {
   443→    return {
   444→      primary_category: 'unclassified',
   445→      secondary_categories: [],
   446→      confidence: 0.5,
   447→      reasoning: `No categories scored above 0. Skip reason: ${skipReason}`,
   448→      category_scores: enhancedScores,
   449→    };
   450→  }
   451→
   452→  const primaryCategory = sortedCategories[0][0];
   453→  const primaryScore = sortedCategories[0][1];
   454→
   455→  // Determine secondary categories (score > 3 and not primary)
   456→  const secondaryCategories = sortedCategories
   457→    .slice(1)
   458→    .filter(([, score]) => score > 3)
   459→    .map(([category]) => category);
   460→
   461→  // Calculate confidence based on score magnitude and separation
   462→  const confidence = Math.min(0.95, Math.max(0.5, primaryScore / 20));
   463→
   464→  return {
   465→    primary_category: primaryCategory,
   466→    secondary_categories: secondaryCategories,
   467→    confidence,
   468→    reasoning: `Direct classification: ${skipReason}. Primary category "${primaryCategory}" scored ${primaryScore.toFixed(2)}`,
   469→    category_scores: enhancedScores,
   470→  };
   471→}
   472→
   473→/**
   474→ * Interpolate classification prompt template with enhanced scores and extracted features
   475→ *
   476→ * Reuses template interpolation utilities from ai-feature-extraction.ts
   477→ */
   478→function interpolateClassificationPrompt(
   479→  userPromptTemplate: string[],
   480→  email: EmailMessage,
   481→  enhancedScores: Record<string, number>,
   482→  extractedFeatures: FeatureExtractionData
   483→): string {
   484→  const template = userPromptTemplate.join('\n');
   485→
   486→  // Create interpolation context with all available data
   487→  const context = {
   488→    email: {
   489→      from: formatEmailAddress(email.from),
   490→      subject: email.subject || '',
   491→      body: getEmailBodyText(email),
   492→    },
   493→    candidateCategories: formatObjectForTemplate(enhancedScores),
   494→    extractedFeatures: formatObjectForTemplate(extractedFeatures as unknown as Record<string, unknown>),
   495→  };
   496→
   497→  // Perform template interpolation using dynamic path resolution
   498→  return interpolateTemplate(template, context);
   499→}
   500→
   501→/**
   502→ * Validate AI response structure matches expected schema
   503→ */
   504→function validateAIResponse(response: Record<string, unknown>): void {
   505→  if (!response || typeof response !== 'object') {
   506→    throw new Error('AI response must be an object');
   507→  }
   508→
   509→  if (!response.primary_category || typeof response.primary_category !== 'string') {
   510→    throw new Error('AI response must include primary_category as string');
   511→  }
   512→
   513→  if (
   514→    response.confidence !== undefined &&
   515→    (typeof response.confidence !== 'number' || response.confidence < 0 || response.confidence > 1)
   516→  ) {
   517→    throw new Error('AI response confidence must be a number between 0 and 1');
   518→  }
   519→
   520→  if (response.secondary_categories !== undefined && !Array.isArray(response.secondary_categories)) {
   521→    throw new Error('AI response secondary_categories must be an array');
