   366→
   367→/**
   368→ * Extract alternative categories that were not selected
   369→ */
   370→function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
   371→  category: string;
   372→  score: number;
   373→  eliminationReason: string;
   374→}> {
   375→  const alternatives: Array<{
   376→    category: string;
   377→    score: number;
   378→    eliminationReason: string;
   379→  }> = [];
   380→
   381→  const finalPrimary = pipelineResults.finalDecision.assignedLabels.primary;
   382→  const finalSecondary = pipelineResults.finalDecision.assignedLabels.secondary;
   383→  const selectedCategories = [finalPrimary, ...finalSecondary];
   384→
   385→  // Get all categories from rule scoring
   386→  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);
   387→
   388→  for (const [category, score] of allCategories) {
   389→    if (!selectedCategories.includes(category)) {
   390→      let eliminationReason = 'Score below selection threshold';
   391→
   392→      // Check if filtered by multi-label selection
   393→      const filteredLabels = pipelineResults.finalDecision.explainabilityTrace.filteredLabels || [];
   394→      const wasFiltered = filteredLabels.find((f) => f.category === category);
   395→      if (wasFiltered) {
   396→        eliminationReason = wasFiltered.filterReason;
   397→      }
   398→
   399→      alternatives.push({
   400→        category,
   401→        score,
   402→        eliminationReason,
   403→      });
   404→    }
   405→  }
   406→
   407→  // Sort by score descending
   408→  alternatives.sort((a, b) => b.score - a.score);
   409→
   410→  return alternatives;
   411→}
   412→
   413→/**
   414→ * Convert rule evaluation results to category rule results for explainability trace
   415→ */
   416→function convertRuleScoringResults(
   417→  ruleEvaluations: RuleEvaluationResult[] | undefined,
   418→  categoryScores: Record<string, number>,
   419→  _subtypeScores: Record<string, Record<string, number>>
   420→): CategoryRuleResult[] {
   421→  if (!ruleEvaluations || ruleEvaluations.length === 0) {
   422→    return [];
   423→  }
