/**
 * Audit Trail Generation Stage
 *
 * Stage 9+ (post-processing) of the EmailCategorizer pipeline. Generates complete
 * explainability traces consolidating results from all 9 classification pipeline stages.
 *
 * This stage is responsible for:
 * - Aggregating results from all pipeline stages into a unified explainability trace
 * - Tracking performance metadata (stage timings, parallel execution maps)
 * - Collecting configuration references used throughout the pipeline
 * - Generating final decision rationale summarizing the complete classification process
 * - Producing database-compatible JSON format for persistence
 *
 * Reference: PrepareRuleScoringPersistenceNode.js and other Prepare*PersistenceNode.js files
 * Document: SCORING_LOGIC.md "Explainability Trace Structure" section
 */

import { z } from 'zod';
import { EmailMessage, ClassificationSession } from '../types';
import {
  ExplainabilityTrace,
  HardAssertionResult,
  StrongIndicatorResult,
  RuleEvaluationResult,
  CategoryRuleResult,
  SubtypeScore,
  RuleScoringMatch,
  AttributeDetectionResult,
  AttributeInfluenceResult,
  DisambiguationResult,
  MultiLabelResult as ExplainMultiLabelResult,
  AIRoutingResult,
} from '../types/explainability-trace';
import { MultiLabelSelectionResult } from './types';
import { FinalDecisionResult } from './final-decision';
import { validateEmailInput, validateSessionInput } from '../utils/validation';

// Zod schema for audit trail configuration
export const AuditTrailConfigSchema = z.object({
  includePerformanceMetrics: z.boolean().default(true),
  includeConfigurationRefs: z.boolean().default(true),
  serializationFormat: z.enum(['json', 'jsonb']).default('json'),
});

// Configuration interface for audit trail generation
export interface AuditTrailConfig {
  includePerformanceMetrics: boolean;
  includeConfigurationRefs: boolean;
  serializationFormat: 'json' | 'jsonb';
}

// Pipeline results interface aggregating all stage outputs
export interface PipelineResults {
  hardAssertions: HardAssertionsStageResult;
  strongIndicators: StrongIndicatorsStageResult;
  ruleScoring: RuleScoringStageResult;
  attributeDetection: AttributeDetectionStageResult;
  attributeInfluence: AttributeInfluenceStageResult;
  disambiguation: DisambiguationStageResult;
  multiLabelSelection: MultiLabelSelectionResult;
  aiRouting: AIRoutingStageResult;
  finalDecision: FinalDecisionResult;
}

// Individual stage result interfaces (for audit trail aggregation purposes)
export interface HardAssertionsStageResult {
  appliedAssertions: HardAssertionResult[];
  processingDurationMs: number;
}

export interface StrongIndicatorsStageResult {
  appliedIndicators: StrongIndicatorResult[];
  processingDurationMs: number;
}

export interface RuleScoringStageResult {
  categoryScores: Record<string, number>;
  subtypeScores: Record<string, Record<string, number>>;
  ruleMatches?: RuleEvaluationResult[];
  processingDurationMs: number;
}

export interface AttributeDetectionStageResult {
  detectedAttributes: AttributeDetectionResult[];
  processingDurationMs: number;
}

export interface AttributeInfluenceStageResult {
  appliedInfluences: AttributeInfluenceResult[];
  processingDurationMs: number;
}

export interface DisambiguationStageResult {
  adjustments: DisambiguationResult[];
  processingDurationMs: number;
}

export interface AIRoutingStageResult {
  routingDecision: 'skip_ai' | 'feature_extraction' | 'full_classification';
  highConfidenceThreshold: number;
  aiRequiredThreshold: number;
  skipConditions: string[];
  aiResponse?: {
    extractedFeatures?: object;
    suggestedCategories?: string[];
    confidence: number;
    reasoning: string;
  };
  reason: string;
  processingDurationMs: number;
}

// Complete audit trail result
export interface AuditTrailResult {
  sessionId: string;
  emailId: string;
  explainabilityTrace: ExplainabilityTrace;
  processingDurationMs: number;
}

/**
 * Generate Audit Trail
 *
 * Consolidates results from all 9 pipeline stages into a complete explainability trace
 * for database persistence and debugging purposes.
 *
 * @param email - Email message being classified
 * @param session - Classification session metadata
 * @param pipelineResults - Results from all 9 pipeline stages
 * @param config - Audit trail configuration
 * @returns Complete audit trail with explainability trace
 */
export function generateAuditTrail(
  email: EmailMessage,
  session: ClassificationSession,
  pipelineResults: PipelineResults,
  config: AuditTrailConfig
): AuditTrailResult {
  const startTime = Date.now();

  // Validate inputs
  validateInputs(email, session, pipelineResults);

  // Extract session and email IDs (support both id and legacy _id formats)
  const sessionId = session.id || ((session as unknown as Record<string, unknown>).session_id as string);
  const emailId = email.id || ((email as unknown as Record<string, unknown>).gmail_id as string);

  // Aggregate stage timings
  const stageTimings = aggregateStageTimings(pipelineResults);

  // Build parallel execution map
  const parallelExecutionMap = buildParallelExecutionMap(pipelineResults);

  // Collect configuration references
  const configurationRefs = config.includeConfigurationRefs ? collectConfigurationReferences(pipelineResults) : {};

  // Generate final decision reason
  const finalDecisionReason = generateFinalDecisionReason(pipelineResults);

  // Extract alternative categories
  const alternativeCategories = extractAlternativeCategories(pipelineResults);

  // Convert multi-label selection results to explainability format
  const multiLabelResults = convertMultiLabelResults(pipelineResults.multiLabelSelection);

  // Convert rule scoring results to category rule results
  const ruleScoringResults = convertRuleScoringResults(
    pipelineResults.ruleScoring.ruleMatches,
    pipelineResults.ruleScoring.categoryScores,
    pipelineResults.ruleScoring.subtypeScores
  );

  // Build AI routing result
  const aiRoutingResult = buildAIRoutingResult(pipelineResults.aiRouting);

  // Construct complete explainability trace
  const explainabilityTrace: ExplainabilityTrace = {
    sessionId,
    emailId,
    hardAssertions: pipelineResults.hardAssertions.appliedAssertions,
    strongIndicators: pipelineResults.strongIndicators.appliedIndicators,
    ruleScoring: ruleScoringResults,
    attributeDetection: pipelineResults.attributeDetection.detectedAttributes,
    attributeInfluence: pipelineResults.attributeInfluence.appliedInfluences,
    disambiguation: pipelineResults.disambiguation.adjustments,
    multiLabelSelection: multiLabelResults,
    aiRouting: aiRoutingResult,
    stageTimings,
    parallelExecutionMap,
    configurationRefs,
    finalDecisionReason,
    alternativeCategories,
  };

  return {
    sessionId,
    emailId,
    explainabilityTrace,
    processingDurationMs: Date.now() - startTime,
  };
}

/**
 * Validate input parameters
 */
function validateInputs(email: EmailMessage, session: ClassificationSession, pipelineResults: PipelineResults): void {
  validateEmailInput(email);
  validateSessionInput(session);

  if (!pipelineResults || typeof pipelineResults !== 'object') {
    throw new Error('Invalid pipeline results: object required');
  }

  // Validate required stages
  const requiredStages = [
    'hardAssertions',
    'strongIndicators',
    'ruleScoring',
    'attributeDetection',
    'attributeInfluence',
    'disambiguation',
    'multiLabelSelection',
    'aiRouting',
    'finalDecision',
  ];

  for (const stage of requiredStages) {
    if (!pipelineResults[stage as keyof PipelineResults]) {
      throw new Error(`Missing required pipeline stage: ${stage}`);
    }
  }
}

/**
 * Aggregate stage timings from all pipeline stages
 */
function aggregateStageTimings(pipelineResults: PipelineResults): Record<string, number> {
  return {
    hardAssertions: pipelineResults.hardAssertions.processingDurationMs,
    strongIndicators: pipelineResults.strongIndicators.processingDurationMs,
    ruleScoring: pipelineResults.ruleScoring.processingDurationMs,
    attributeDetection: pipelineResults.attributeDetection.processingDurationMs,
    attributeInfluence: pipelineResults.attributeInfluence.processingDurationMs,
    disambiguation: pipelineResults.disambiguation.processingDurationMs,
    multiLabelSelection: pipelineResults.multiLabelSelection.processingDurationMs,
    aiRouting: pipelineResults.aiRouting.processingDurationMs,
    finalDecision: pipelineResults.finalDecision.processingDurationMs,
  };
}

/**
 * Build parallel execution map tracking which stages/attributes ran concurrently
 */
function buildParallelExecutionMap(pipelineResults: PipelineResults): Record<string, string[]> {
  const parallelMap: Record<string, string[]> = {};

  // Track parallel-processed attributes from attribute detection stage
  const parallelAttributes = pipelineResults.attributeDetection.detectedAttributes
    .filter((attr) => attr.parallelProcessed)
    .map((attr) => attr.attribute);

  if (parallelAttributes.length > 0) {
    parallelMap.attributeDetection = parallelAttributes;
  }

  return parallelMap;
}

/**
 * Collect configuration references used throughout the pipeline
 */
function collectConfigurationReferences(pipelineResults: PipelineResults): Record<string, string> {
  const refs: Record<string, string> = {};

  // Hard assertions config
  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
    refs.hardAssertions = 'config.processing_config.category_signals.*.hard_assertions';
  }

  // Strong indicators config
  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
    refs.strongIndicators = 'config.processing_config.category_signals.*.strong_indicators';
  }

  // Rule scoring config
  if (Object.keys(pipelineResults.ruleScoring.categoryScores).length > 0) {
    refs.ruleScoring = 'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';
  }

  // Attribute detection config
  if (pipelineResults.attributeDetection.detectedAttributes.length > 0) {
    refs.attributeDetection = 'config.processing_config.attributes.detectors';
  }

  // Attribute influence config
  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
    refs.attributeInfluence = 'config.processing_config.attribute_relevance';
  }

  // Disambiguation config
  if (pipelineResults.disambiguation.adjustments.length > 0) {
    refs.disambiguation = 'config.processing_config.settings.disambiguation.confidence_gap_threshold';
  }

  // Multi-label selection config
  refs.multiLabelSelection = 'config.processing_config.multi_label_policy';

  // AI routing config
  refs.aiRouting = 'config.processing_config.confidence_thresholds';

  // Final decision config
  refs.finalDecision = 'config.processing_config.settings.archive_threshold';

  return refs;
}

/**
 * Generate final decision reason summarizing the complete classification pipeline
 */
function generateFinalDecisionReason(pipelineResults: PipelineResults): string {
  const reasons: string[] = [];

  // Check for hard assertions (highest priority)
  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
    const categories = pipelineResults.hardAssertions.appliedAssertions.map((a) => a.category);
    reasons.push(`Hard assertion matched for categories: ${Array.from(new Set(categories)).join(', ')}`);
  }

  // Check for strong indicators
  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
    const categories = pipelineResults.strongIndicators.appliedIndicators.map((i) => i.category);
    reasons.push(`Strong indicators detected for: ${Array.from(new Set(categories)).join(', ')}`);
  }

  // Include rule scoring results
  const topCategories = Object.entries(pipelineResults.ruleScoring.categoryScores)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  if (topCategories.length > 0) {
    const categoryScores = topCategories.map(([cat, score]) => `${cat}:${score.toFixed(1)}`).join(', ');
    reasons.push(`Top rule-based scores: ${categoryScores}`);
  }

  // Include attribute influences
  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
    const attributeCount = pipelineResults.attributeInfluence.appliedInfluences.length;
    reasons.push(`${attributeCount} attribute bonuses applied`);
  }

  // Include AI routing decision
  if (pipelineResults.aiRouting.routingDecision !== 'skip_ai') {
    reasons.push(`AI classification used: ${pipelineResults.aiRouting.reason}`);
  }

  // Include final decision
  const finalLabels = pipelineResults.finalDecision.assignedLabels;
  reasons.push(`Final assignment: primary=${finalLabels.primary}, secondary=[${finalLabels.secondary.join(', ')}]`);

  if (pipelineResults.finalDecision.determinedActions.length > 0) {
    reasons.push(`Actions: ${pipelineResults.finalDecision.determinedActions.join(', ')}`);
  }

  return reasons.join('; ');
}

/**
 * Extract alternative categories that were not selected
 */
function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
  category: string;
  score: number;
  eliminationReason: string;
}> {
  const alternatives: Array<{
    category: string;
    score: number;
    eliminationReason: string;
  }> = [];

  const finalPrimary = pipelineResults.finalDecision.assignedLabels.primary;
  const finalSecondary = pipelineResults.finalDecision.assignedLabels.secondary;
  const selectedCategories = [finalPrimary, ...finalSecondary];

  // Get all categories from rule scoring
  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);

  for (const [category, score] of allCategories) {
    if (!selectedCategories.includes(category)) {
      let eliminationReason = 'Score below selection threshold';

      // Check if filtered by multi-label selection
      const filteredLabels = pipelineResults.finalDecision.explainabilityTrace.filteredLabels || [];
      const wasFiltered = filteredLabels.find((f) => f.category === category);
      if (wasFiltered) {
        eliminationReason = wasFiltered.filterReason;
      }

      alternatives.push({
        category,
        score,
        eliminationReason,
      });
    }
  }

  // Sort by score descending
  alternatives.sort((a, b) => b.score - a.score);

  return alternatives;
}

/**
 * Convert rule evaluation results to category rule results for explainability trace
 */
function convertRuleScoringResults(
  ruleEvaluations: RuleEvaluationResult[] | undefined,
  categoryScores: Record<string, number>,
  _subtypeScores: Record<string, Record<string, number>>
): CategoryRuleResult[] {
  if (!ruleEvaluations || ruleEvaluations.length === 0) {
    return [];
  }

  // Group rule evaluations by category
  const categoryGroups = new Map<string, RuleEvaluationResult[]>();
  for (const evaluation of ruleEvaluations) {
    const existing = categoryGroups.get(evaluation.category) || [];
    existing.push(evaluation);
    categoryGroups.set(evaluation.category, existing);
  }

  // Convert each category group to CategoryRuleResult
  const categoryResults: CategoryRuleResult[] = [];
  for (const [categoryCode, evaluations] of Array.from(categoryGroups.entries())) {
    // Aggregate all rule matches across subtypes
    const allRuleMatches: RuleScoringMatch[] = [];
    const subtypeScoresMap: Record<string, SubtypeScore> = {};

    for (const evaluation of evaluations) {
      // Convert RuleMatch[] to RuleScoringMatch[]
      const scoringMatches: RuleScoringMatch[] = evaluation.matchedRules.map((match) => ({
        ...match,
        tier: (evaluation.tier === 'high'
          ? 'high_confidence'
          : evaluation.tier === 'medium'
            ? 'medium_confidence'
            : 'low_confidence') as 'high_confidence' | 'medium_confidence' | 'low_confidence',
        values: [match.matchedValue],
        weight: match.ruleWeight,
        ruleId: `${evaluation.category}_${evaluation.subtype}_${match.field}`,
      }));

      allRuleMatches.push(...scoringMatches);

      // Build subtype score entry
      subtypeScoresMap[evaluation.subtype] = {
        totalScore: evaluation.cappedScore,
        ruleMatches: scoringMatches,
        aggregationBreakdown: evaluation.reason,
      };
    }

    // Find the subtype with highest score
    const subtypeEntries = Object.entries(subtypeScoresMap);
    const selectedSubtype =
      subtypeEntries.length > 0
        ? subtypeEntries.reduce(
            (max, [id, score]) => (score.totalScore > max.score ? { id, score: score.totalScore } : max),
            { id: subtypeEntries[0][0], score: subtypeEntries[0][1].totalScore }
          )
        : null;

    // Get category aggregated score from categoryScores
    const aggregatedScore = categoryScores[categoryCode] || 0;

    // Build scoring rationale
    const scoringRationale = evaluations.map((e) => e.reason);

    categoryResults.push({
      categoryCode,
      aggregatedScore,
      subtypeScores: subtypeScoresMap,
      ruleMatches: allRuleMatches,
      scoringRationale,
      selectedSubtypeId: selectedSubtype?.id || null,
      confidence: aggregatedScore / 100, // Convert score to confidence (0-1 range)
    });
  }

  return categoryResults;
}

/**
 * Convert multi-label selection results to explainability format
 */
function convertMultiLabelResults(multiLabelResult: MultiLabelSelectionResult): ExplainMultiLabelResult[] {
  return multiLabelResult.selectedLabels.map((label) => ({
    selectedCategories: [label.category],
    rejectedCategories: [],
    coPresenceRulesApplied: [],
    maxLabelsLimit: 1,
    minSecondaryConfidence: 0,
    reason: label.selectionRationale,
  }));
}

/**
 * Build AI routing result for explainability trace
 */
function buildAIRoutingResult(aiRoutingResult: AIRoutingStageResult): AIRoutingResult | undefined {
  // AI routing is optional - only include if AI was actually used
  if (aiRoutingResult.routingDecision === 'skip_ai' && !aiRoutingResult.aiResponse) {
    return {
      routingDecision: aiRoutingResult.routingDecision,
      highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
      aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
      skipConditions: aiRoutingResult.skipConditions,
      reason: aiRoutingResult.reason,
    };
  }

  return {
    routingDecision: aiRoutingResult.routingDecision,
    highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
    aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
    skipConditions: aiRoutingResult.skipConditions,
    aiResponse: aiRoutingResult.aiResponse,
    reason: aiRoutingResult.reason,
  };
}

/**
 * Classification Pipeline Orchestrator (MINIMAL MVP for Phase 3.5.2)
 *
 * This is a MINIMAL implementation for T036i establishing the basic orchestration pattern.
 * Full integration with all 9 stages and proper config mapping will be completed in Phase 3.6 (T040-T041).
 *
 * Current Implementation:
 * - Demonstrates sequential stage execution pattern
 * - Establishes context propagation architecture
 * - Provides basic error handling and performance tracking
 * - Returns classification results in expected format
 *
 * Phase 3.6 Enhancements:
 * - Complete config mapping from ProcessingConfig to individual stage configs
 * - Full 9-stage pipeline with AI routing, feature extraction, and final decision
 * - Advanced error handling with partial failure recovery
 * - Batch processing optimization
 */

import { EmailMessage } from '../types/email-message';
import { ProcessingConfig } from '../types/category-configuration';
import { ClassificationResult } from '../types/classification-result';

// Validation utilities
import { validateEmailInput, validateConfigInput } from '../utils/validation';

/**
 * Error result for batch processing when individual email fails
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

/**
 * Classification Pipeline orchestrator
 *
 * Manages sequential execution of classification stages with proper context
 * propagation, error handling, and performance tracking.
 */
export class ClassificationPipeline {
  private readonly config: ProcessingConfig;

  /**
   * Initialize classification pipeline with validated configuration
   *
   * @param config - Complete processing configuration for all stages
   * @throws {Error} If configuration validation fails
   */
  constructor(config: ProcessingConfig) {
    // Validate configuration
    validateConfigInput(config);

    // Validate confidence thresholds specifically
    const { confidence_thresholds } = config;
    if (
      !confidence_thresholds ||
      confidence_thresholds.high_confidence < 0 ||
      confidence_thresholds.medium_confidence < 0 ||
      confidence_thresholds.low_confidence < 0 ||
      confidence_thresholds.secondary_label_min_gap < 0
    ) {
      throw new Error('Invalid confidence thresholds: all values must be non-negative');
    }

    // Store config for Phase 3.6 when full stage integration happens
    this.config = config;
  }

  /**
   * Get configuration (for testing and future stage integration)
   */
  getConfig(): ProcessingConfig {
    return this.config;
  }

  /**
   * Execute classification pipeline on single email (MINIMAL MVP)
   *
   * This minimal implementation:
   * 1. Validates inputs
   * 2. Returns a basic classification result
   * 3. Demonstrates the expected interface
   *
   * Full stage-by-stage execution will be implemented in Phase 3.6.
   *
   * @param email - Email message to classify
   * @returns Complete classification result with selected labels
   * @throws {Error} If email validation fails
   */
  async classify(email: EmailMessage): Promise<ClassificationResult> {
    const pipelineStartTime = Date.now();

    try {
      // Validate email input
      validateEmailInput(email);

      // MINIMAL MVP: Return placeholder result
      // Full pipeline execution (stages 1-9) will be implemented in Phase 3.6
      const pipelineEndTime = Date.now();
      const totalDuration = pipelineEndTime - pipelineStartTime;

      return {
        id: `classification-${email.id}-${Date.now()}`,
        emailId: email.id,
        sessionId: 'mvp-session',
        primaryCategory: '',
        secondaryCategories: [],
        confidence: 0,
        explainabilityTrace: {
          sessionId: 'mvp-session',
          emailId: email.id,
          hardAssertions: [],
          strongIndicators: [],
          ruleScoring: [],
          attributeDetection: [],
          attributeInfluence: [],
          disambiguation: [],
          multiLabelSelection: [],
          stageTimings: {},
          parallelExecutionMap: {},
          configurationRefs: {},
          finalDecisionReason: 'MVP placeholder - full pipeline not yet implemented',
          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: email.id,
          categoryScores: {},
          stageContributions: {},
          disambiguationApplied: [],
          parallelComputationMetrics: {
            totalParallelOperations: 0,
            parallelEfficiencyScore: 0,
            bottleneckStages: [],
            peakMemoryUsageMB: 0,
            averageCpuUtilization: 0,
            concurrentOperationsPeak: 0,
            parallelizableButSequential: [],
            parallelConflicts: [],
          },
        },
        attributeContext: {
          emailId: email.id,
          urgency: 'low',
          domains: [],
          structuralPatterns: [],
          temporalSignals: [],
          detectionMetadata: {},
          influenceApplications: [],
          derivedAttributes: {},
          attributeRelationships: [],
        },
        processedAt: new Date(),
        processingDurationMs: totalDuration,
        aiRoutingUsed: false,
        batchPosition: 0,
        parallelStageResults: [],
      };
    } catch (error) {
      // Capture error with processing time
      const pipelineEndTime = Date.now();
      throw new Error(
        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Process multiple emails sequentially
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    for (const email of emails) {
      const startTime = Date.now();
      try {
        const result = await this.classify(email);
        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    return results;
  }
}

/**
 * Classification Session and Result Initialization Utilities
 *
 * Provides factory functions for creating and updating classification entities
 * following the canonical signature pattern for all pipeline stages.
 *
 * CANONICAL SIGNATURE TARGET:
 * (email: EmailMessage, session: ClassificationSession, result: ClassificationResult, config: StageConfig) => StageResult
 *
 * CHARTER:
 * - ClassificationSession = "I processed a batch of emails" (batch-level metadata)
 * - ClassificationResult = "Here's everything about how I classified this one email" (per-email results)
 */

import { randomUUID, createHash } from 'crypto';
import {
  ClassificationSession,
  ClassificationResult,
  ProcessingConfig,
  ExplainabilityTrace,
  ScoreBreakdown,
  AttributeContext,
} from '../types';

/**
 * Creates a new classification session for batch email processing
 *
 * @param config - Processing configuration for the session
 * @param processingMode - Mode of processing: 'parallel' or 'sequential'
 * @param batchSize - Number of emails to process in this session
 * @returns Initialized ClassificationSession with default metrics
 */
export function createClassificationSession(
  config: ProcessingConfig,
  processingMode: 'parallel' | 'sequential' = 'parallel',
  batchSize: number = 0
): ClassificationSession {
  return {
    id: generateUuid(),
    startedAt: new Date(),
    completedAt: undefined,
    emailCount: batchSize,
    successCount: 0,
    errorCount: 0,

    processingMode,
    batchSize,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },

    configVersion: config.version.toString(),
    configSnapshot: config as object,

    errors: [],
    warnings: [],
  };
}

/**
 * Creates a new classification result for a single email
 *
 * @param emailId - Gmail message ID being classified
 * @param sessionId - ID of the classification session this email belongs to
 * @param batchPosition - Position of this email in the batch (0-indexed)
 * @returns Initialized ClassificationResult with empty traces
 */
export function createClassificationResult(
  emailId: string,
  sessionId: string,
  batchPosition: number = 0
): ClassificationResult {
  return {
    id: generateUuid(),
    emailId,
    sessionId,

    // Classification results (to be populated by pipeline stages)
    primaryCategory: '',
    secondaryCategories: [],
    confidence: 0,

    // Enhanced explainability (initialized empty, populated by stages)
    explainabilityTrace: createEmptyExplainabilityTrace(),
    scoreBreakdown: createEmptyScoreBreakdown(),
    attributeContext: createEmptyAttributeContext(),

    // Processing metadata
    processedAt: new Date(),
    processingDurationMs: 0,
    aiRoutingUsed: false,

    // Parallel processing context
    batchPosition,
    parallelStageResults: [],
  };
}

/**
 * Updates a classification result with a stage's output
 *
 * This utility function merges stage results into the ongoing ClassificationResult,
 * preserving existing data while adding new stage-specific information.
 *
 * NOTE: This is a LEGACY/BRIDGE function for stages that haven't migrated to the canonical
 * signature pattern. Canonical signature stages mutate result directly and don't need this helper.
 *
 * CANONICAL SIGNATURE PATTERN:
 * - Stages receive: (email, session, result, config)
 * - Stages mutate result.scoreBreakdown, result.explainabilityTrace, etc. directly
 * - Stages return void
 *
 * LEGACY PATTERN (this function):
 * - Stages return stageResult object
 * - This function merges stageResult into result
 *
 * @param result - The classification result to update (mutated in place)
 * @param stageResult - The result from a legacy pipeline stage
 * @param stageName - Name of the stage that produced this result
 * @returns void (mutates result in place for performance)
 *
 * @deprecated Use canonical signature pattern where stages mutate result directly
 */
export function updateResultWithStageOutput(
  result: ClassificationResult,
  stageResult: Record<string, unknown>,
  stageName: string
): void {
  // Update explainability trace with stage-specific reasoning
  // Note: ExplainabilityTrace uses specific stage arrays, not a generic 'stages' object

  // Update score breakdown if stage provides score updates
  if (stageResult.updatedScores) {
    const scores = stageResult.updatedScores as Record<string, number>;
    Object.entries(scores).forEach(([category, score]) => {
      result.scoreBreakdown.categoryScores[category] = {
        baseScore: score,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: score,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    });
  }

  // Track processing duration for this stage
  if (typeof stageResult.processingDurationMs === 'number') {
    result.processingDurationMs += stageResult.processingDurationMs;
  }

  // Update parallel stage results if applicable
  if (stageResult.parallelExecution && typeof stageResult.parallelExecution === 'object') {
    const parallelInfo = stageResult.parallelExecution as Record<string, unknown>;
    result.parallelStageResults.push({
      stageId: generateUuid(),
      stageName,
      executionTimeMs: (stageResult.processingDurationMs as number) || 0,
      parallelWithStages: (parallelInfo.parallelWith as string[]) || [],
      dependentOnStages: (parallelInfo.dependencies as string[]) || [],
      cacheHitsCount: (parallelInfo.cacheHits as number) || 0,
      errorCount: (parallelInfo.errors as number) || 0,
    });
  }

  // Update AI routing flag if this was an AI stage
  if (stageName.includes('ai_') || stageName.includes('ai-')) {
    result.aiRoutingUsed = true;
  }
}

/**
 * Finalizes a classification session after all emails are processed
 *
 * @param session - The session to finalize (mutated in place)
 * @returns void (mutates session in place for performance)
 */
export function finalizeClassificationSession(session: ClassificationSession): void {
  session.completedAt = new Date();

  // Calculate final performance metrics
  const totalDurationMs = session.completedAt.getTime() - session.startedAt.getTime();
  session.performanceMetrics.totalDurationMs = totalDurationMs;

  if (session.successCount > 0) {
    session.performanceMetrics.avgEmailDurationMs = totalDurationMs / session.successCount;
  }
}

/**
 * Increments the success count for a classification session
 *
 * @param session - The session to update (mutated in place)
 * @returns void (mutates session in place for performance)
 */
export function incrementSessionSuccess(session: ClassificationSession): void {
  session.successCount += 1;
}

/**
 * Increments the error count and records an error for a classification session
 *
 * @param session - The session to update (mutated in place)
 * @param emailId - ID of the email that failed
 * @param stage - Name of the stage where the error occurred
 * @param error - Error message or Error object
 * @param recoverable - Whether the error is recoverable
 * @returns void (mutates session in place for performance)
 */
export function incrementSessionError(
  session: ClassificationSession,
  emailId: string,
  stage: string,
  error: string | Error,
  recoverable: boolean = false
): void {
  session.errorCount += 1;
  session.errors.push({
    emailId,
    stage,
    error: error instanceof Error ? error.message : error,
    timestamp: new Date(),
    recoverable,
    retryCount: 0,
  });
}

/**
 * Adds a warning to a classification session
 *
 * @param session - The session to update (mutated in place)
 * @param emailId - ID of the email that triggered the warning
 * @param stage - Name of the stage where the warning occurred
 * @param warning - Warning message
 * @param impact - Impact level: 'low', 'medium', or 'high'
 * @returns void (mutates session in place for performance)
 */
export function addSessionWarning(
  session: ClassificationSession,
  emailId: string,
  stage: string,
  warning: string,
  impact: 'low' | 'medium' | 'high' = 'low'
): void {
  session.warnings.push({
    emailId,
    stage,
    warning,
    timestamp: new Date(),
    impact,
  });
}

// Private helper functions

/**
 * Generates a UUID v4 compatible identifier
 *
 * @returns UUID v4 string
 */
function generateUuid(): string {
  return randomUUID();
}

/**
 * Hashes a processing configuration for versioning and reproducibility
 *
 * @param config - Processing configuration to hash
 * @returns SHA-256 hash of the configuration
 *
 * @internal Currently unused but reserved for future config versioning
 */
// eslint-disable-next-line @typescript-eslint/no-unused-vars
function hashConfig(config: ProcessingConfig): string {
  const configJson = JSON.stringify(config, Object.keys(config).sort());
  return createHash('sha256').update(configJson).digest('hex').substring(0, 16);
}

/**
 * Creates an empty explainability trace for initialization
 *
 * @returns Empty ExplainabilityTrace matching the actual type structure
 */
function createEmptyExplainabilityTrace(): ExplainabilityTrace {
  return {
    sessionId: '',
    emailId: '',
    hardAssertions: [],
    strongIndicators: [],
    ruleScoring: [],
    attributeDetection: [],
    attributeInfluence: [],
    disambiguation: [],
    multiLabelSelection: [],
    aiRouting: undefined,
    stageTimings: {},
    parallelExecutionMap: {},
    configurationRefs: {},
    finalDecisionReason: '',
    alternativeCategories: [],
  };
}

/**
 * Creates an empty score breakdown for initialization
 *
 * @returns Empty ScoreBreakdown matching the actual type structure
 */
function createEmptyScoreBreakdown(): ScoreBreakdown {
  return {
    emailId: '',
    categoryScores: {},
    stageContributions: {},
    disambiguationApplied: [],
    parallelComputationMetrics: {
      totalParallelOperations: 0,
      parallelEfficiencyScore: 0,
      bottleneckStages: [],
      peakMemoryUsageMB: 0,
      averageCpuUtilization: 0,
      concurrentOperationsPeak: 0,
      parallelizableButSequential: [],
      parallelConflicts: [],
    },
  };
}

/**
 * Creates an empty attribute context for initialization
 *
 * @returns Empty AttributeContext matching the actual type structure
 */
function createEmptyAttributeContext(): AttributeContext {
  return {
    emailId: '',
    urgency: 'low',
    domains: [],
    structuralPatterns: [],
    temporalSignals: [],
    detectionMetadata: {},
    influenceApplications: [],
    derivedAttributes: {},
    attributeRelationships: [],
  };
}

/**
 * Ensures a category score entry exists in the scoreBreakdown, initializing if needed
 *
 * This is the canonical way to initialize category scores across all pipeline stages.
 * Called by stages when they first encounter a category to ensure the score structure exists.
 *
 * @param result - Classification result to update (mutated in place)
 * @param categoryKey - Category identifier (e.g., "financial" or "financial.credit_card")
 */
export function ensureCategoryScoreInitialized(result: ClassificationResult, categoryKey: string): void {
  if (!result.scoreBreakdown.categoryScores[categoryKey]) {
    result.scoreBreakdown.categoryScores[categoryKey] = {
      baseScore: 0,
      hardAssertionBonus: 0,
      strongIndicatorScore: 0,
      ruleScore: 0,
      attributeInfluenceScore: 0,
      finalScore: 0,
      parallelComputedComponents: [],
      computationDurationMs: 0,
      cacheHits: [],
      scoreAggregationSteps: [],
      cappingApplied: false,
    };
  }
}

