          finalDecisionReason: 'MVP placeholder - full pipeline not yet implemented',
          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: email.id,
          categoryScores: {},
          stageContributions: {},
          disambiguationApplied: [],
          parallelComputationMetrics: {
            totalParallelOperations: 0,
            parallelEfficiencyScore: 0,
            bottleneckStages: [],
            peakMemoryUsageMB: 0,
            averageCpuUtilization: 0,
            concurrentOperationsPeak: 0,
            parallelizableButSequential: [],
            parallelConflicts: [],
          },
        },
        attributeContext: {
          emailId: email.id,
          urgency: 'low',
          domains: [],
