          attributeDetectors: this.config.attributes?.detectors || [],
          derivedAttributes: this.config.attributes?.derived || [],
        });

        executeAttributeInfluence(email, session, result, {
          attributeRelevance: this.config.attribute_relevance || {},
        });

        executeDisambiguation(email, session, result, {
          disambiguationRules: this.config.settings?.disambiguation || {},
          confidenceThresholds: this.config.confidence_thresholds,
        });

        executeMultiLabelSelection(
          email,
          session,
          result,
          this.config.multi_label_policy || {
            maxLabels: 3,
            minSecondaryConfidence: 0.5,
            allowedCombinations: [],
          },
